<link href="https://fonts.googleapis.com/css2?family=Playfair+Display:wght@500;700&family=DM+Sans:wght@300;400;500&display=swap" rel="stylesheet"/>
<style>
:root{--bg:#f7f6f2;--white:#ffffff;--black:#0f0f0f;--dark:#1a1a1a;--red:#4a9eca;--muted:#888;--border:#e5e3dc;--card:#ffffff;--shadow:0 2px 16px rgba(0,0,0,0.07)}
*{box-sizing:border-box;margin:0;padding:0}
html{scroll-behavior:smooth}
body{font-family:'DM Sans',sans-serif;background:var(--bg);color:var(--dark);font-size:16px;line-height:1.6}
nav{position:sticky;top:0;z-index:200;background:rgba(247,246,242,0.96);backdrop-filter:blur(10px);border-bottom:1px solid var(--border);display:flex;align-items:center;justify-content:space-between;padding:1rem 2.5rem}
.nav-logo{font-family:'Playfair Display',serif;font-size:1.25rem;font-weight:700;color:var(--black);text-decoration:none;cursor:pointer}
.nav-logo span{color:var(--red)}
.nav-links{display:flex;gap:2rem;list-style:none;align-items:center}
.nav-links a{color:var(--muted);text-decoration:none;font-size:.88rem;transition:color .2s}
.nav-links a:hover{color:var(--black)}
.nav-cta{background:var(--black)!important;color:#fff!important;padding:.45rem 1.2rem;border-radius:4px;font-weight:500!important}
.nav-cta:hover{background:var(--red)!important}
.social-links{display:flex;gap:1rem;flex-wrap:wrap;margin-top:1rem}
.social-links a{color:var(--dark);text-decoration:none;border-bottom:1px solid transparent;transition:all .2s}
.social-links a:hover{color:var(--red);border-bottom-color:var(--red)}
.hero{background:#000;border-bottom:1px solid var(--border);position:relative;overflow:hidden;padding:0}
.hero-cars{display:flex;align-items:flex-end;justify-content:center;gap:clamp(.75rem,3vw,2rem);min-height:480px;position:relative}
.hero-car{height:clamp(220px,28vw,320px);width:auto;max-width:34%;object-fit:contain;flex-shrink:0;align-self:flex-end;opacity:0;transition:transform .9s ease,opacity .9s ease,filter .3s ease;filter:drop-shadow(0 14px 28px rgba(0,0,0,.28))}
.hero-car-left{transform:translateX(-90px) scaleX(-1)}
.hero-car-right{transform:translateX(90px) scaleX(-1)}
.hero-car.in-view{opacity:1;transform:translateX(0) scaleX(-1)}
.hero-center{flex:1;text-align:center;padding:4rem 1.5rem 3rem;z-index:2;position:relative}
.hero-eyebrow{font-size:.75rem;letter-spacing:3px;text-transform:uppercase;color:var(--red);margin-bottom:1rem;font-weight:500}
.hero h1{font-family:'Playfair Display',serif;font-size:clamp(2rem,5vw,4rem);line-height:1;font-weight:700;color:#fff;margin-bottom:1.5rem;letter-spacing:-1px}
.hero h1 em{color:var(--red);font-style:normal}
.hero p{max-width:380px;margin:0 auto 2.5rem;color:rgba(255,255,255,0.6);font-size:.95rem;font-weight:300;line-height:1.8}
.hero-btns{display:flex;gap:1rem;justify-content:center;flex-wrap:wrap}
.hero .btn-outline{color:#fff;border-color:rgba(255,255,255,0.4)}
.hero .btn-outline:hover{background:#fff;color:var(--black)}
.ba-stack{display:flex;flex-direction:column;gap:1.25rem;margin-bottom:2.5rem}
.ba-card{background:var(--bg);border:1.5px solid var(--border);border-radius:10px;padding:1.25rem 1.5rem}
.ba-pair{display:grid;grid-template-columns:1fr 1fr;gap:1rem}
.ba-box{border-radius:8px;height:180px;display:flex;align-items:center;justify-content:center;font-size:.85rem;font-weight:500;letter-spacing:1px;text-transform:uppercase}
.ba-before{background:#e8e6e0;color:#999;border:2px dashed #ccc}
.ba-after{background:linear-gradient(135deg,#e8f4fd,#d0eaf9);color:var(--red);border:2px dashed #4a9eca88}
.socials-cta{text-align:center;padding:2rem;background:var(--black);border-radius:12px;color:#fff}
.socials-cta p{font-family:'Playfair Display',serif;font-size:1.4rem;font-weight:700;margin-bottom:.4rem}
.socials-sub{font-family:'DM Sans',sans-serif;font-size:.9rem;color:rgba(255,255,255,.5);margin-bottom:1.5rem!important;font-weight:300}
.socials-links{display:flex;gap:1rem;justify-content:center;flex-wrap:wrap}
.social-btn{display:inline-block;padding:.65rem 1.5rem;border-radius:6px;font-size:.9rem;font-weight:500;text-decoration:none;transition:all .2s;font-family:'DM Sans',sans-serif}
.instagram-btn{background:linear-gradient(135deg,#833ab4,#fd1d1d,#fcb045);color:#fff}
.instagram-btn:hover{opacity:.85;transform:translateY(-2px)}
.facebook-btn{background:#1877f2;color:#fff}
.facebook-btn:hover{opacity:.85;transform:translateY(-2px)}
@media(max-width:700px){.hero-car{display:none}.hero-center{padding:3rem 1rem 2.5rem}.ba-pair{grid-template-columns:1fr}.ba-box{height:120px}}
.btn-primary{background:var(--black);color:#fff;border:none;padding:.8rem 2rem;border-radius:4px;font-size:.95rem;font-weight:500;cursor:pointer;font-family:'DM Sans',sans-serif;transition:background .2s,transform .1s}
.btn-primary:hover{background:var(--red)}
.btn-primary:active{transform:scale(.98)}
.btn-outline{background:transparent;color:var(--black);border:1.5px solid var(--black);padding:.8rem 2rem;border-radius:4px;font-size:.95rem;cursor:pointer;font-family:'DM Sans',sans-serif;transition:all .2s}
.btn-outline:hover{background:var(--black);color:#fff}
.stats{display:flex;justify-content:center;background:var(--black);flex-wrap:wrap}
.stat{flex:1;min-width:150px;max-width:220px;padding:1.6rem 1rem;text-align:center;border-right:1px solid rgba(255,255,255,.08)}
.stat:last-child{border-right:none}
.stat-n{font-family:'Playfair Display',serif;font-size:2rem;font-weight:700;color:#fff;margin-bottom:.2rem}
.stat-l{font-size:.72rem;letter-spacing:2px;text-transform:uppercase;color:rgba(255,255,255,.4)}
section{padding:5rem 2rem}
.sec-label{font-size:.72rem;letter-spacing:3px;text-transform:uppercase;color:var(--red);margin-bottom:.75rem;font-weight:500}
.sec-title{font-family:'Playfair Display',serif;font-size:clamp(1.8rem,4vw,3rem);font-weight:700;color:var(--black);line-height:1.1;margin-bottom:.75rem}
.sec-sub{color:var(--muted);font-size:.95rem;font-weight:300;max-width:480px;margin-bottom:3rem;line-height:1.8}
#services{background:var(--bg)}
.tiers{display:grid;grid-template-columns:repeat(auto-fit,minmax(260px,1fr));gap:1.5rem;max-width:980px}
.tier{background:var(--card);border:1.5px solid var(--border);border-radius:10px;padding:2.2rem;position:relative;transition:box-shadow .2s,transform .2s}
.tier:hover{box-shadow:var(--shadow);transform:translateY(-2px)}
.tier.featured{border-color:var(--black)}
.t-badge{display:inline-block;background:var(--black);color:#fff;font-size:.68rem;letter-spacing:1.5px;text-transform:uppercase;padding:3px 10px;border-radius:2px;margin-bottom:1.2rem}
.t-name{font-family:'Playfair Display',serif;font-size:1.5rem;font-weight:700;color:var(--black);margin-bottom:.3rem}
.t-price{font-size:2.4rem;font-weight:300;color:var(--black);margin-bottom:.3rem;letter-spacing:-1px}
.t-price sup{font-size:1rem;vertical-align:top;margin-top:8px}
.t-price sub{font-size:.8rem;color:var(--muted);font-weight:400}
.t-desc{font-size:.85rem;color:var(--muted);margin-bottom:1.5rem;font-weight:300}
.t-features{list-style:none;margin-bottom:1.8rem}
.t-features li{font-size:.88rem;color:#444;padding:.5rem 0;border-bottom:1px solid var(--border);display:flex;align-items:center;gap:.6rem}
.t-features li::before{content:'';width:5px;height:5px;background:var(--red);border-radius:50%;flex-shrink:0}
.t-btn{width:100%;padding:.7rem;background:transparent;border:1.5px solid var(--border);color:var(--dark);border-radius:4px;cursor:pointer;font-family:'DM Sans',sans-serif;font-size:.9rem;transition:all .2s}
.t-btn:hover{border-color:var(--black);background:var(--black);color:#fff}
.tier.featured .t-btn{background:var(--black);color:#fff;border-color:var(--black)}
.tier.featured .t-btn:hover{background:var(--red);border-color:var(--red)}
.tier.custom-tier{grid-column:1 / -1;border-style:dashed}
.tier.custom-tier .t-desc{max-width:700px}
#about{background:var(--white);border-top:1px solid var(--border)}
.about-grid{display:grid;grid-template-columns:1fr 1fr;gap:4rem;max-width:880px;align-items:center}
.about-text p{color:#555;font-weight:300;margin-bottom:1rem;line-height:1.9}
.about-list{list-style:none}
.about-list li{padding:.65rem 0;border-bottom:1px solid var(--border);font-size:.9rem;color:#444;display:flex;align-items:center;gap:.75rem}
.about-list li::before{content:'';width:6px;height:6px;background:var(--black);border-radius:50%;flex-shrink:0}
#contact{background:var(--bg);border-top:1px solid var(--border)}
.contact-grid{display:grid;grid-template-columns:1fr 1fr;gap:3rem;max-width:800px;align-items:start}
.contact-row{display:flex;gap:.85rem;align-items:flex-start;margin-bottom:1rem}
.c-icon{color:var(--red);font-size:1rem;margin-top:3px}
.c-label{font-size:.72rem;letter-spacing:1.5px;text-transform:uppercase;color:var(--muted);margin-bottom:2px}
.c-val{color:var(--dark);font-size:.95rem}
.c-val a{color:var(--dark);text-decoration:none}
.c-val a:hover{color:var(--red)}
footer{background:var(--black);color:rgba(255,255,255,.4);padding:1.5rem 2.5rem;display:flex;justify-content:space-between;align-items:center;font-size:.8rem;flex-wrap:wrap;gap:.5rem}
.f-logo{font-family:'Playfair Display',serif;font-size:1rem;color:#fff}
.f-logo span{color:var(--red)}
#chat-bubble{position:fixed;bottom:1.5rem;right:1.5rem;z-index:500;display:flex;flex-direction:column;align-items:flex-end}
#chat-toggle{width:56px;height:56px;background:var(--black);color:#fff;border:none;border-radius:50%;cursor:pointer;font-size:1.3rem;box-shadow:0 4px 20px rgba(0,0,0,.2);transition:background .2s,transform .15s;display:flex;align-items:center;justify-content:center}
#chat-toggle:hover{background:var(--red);transform:scale(1.05)}
#chat-win{display:none;flex-direction:column;width:340px;height:520px;background:#fff;border:1.5px solid var(--border);border-radius:12px;overflow:hidden;margin-bottom:.75rem;box-shadow:0 8px 40px rgba(0,0,0,.12)}
#chat-win.open{display:flex}
#chat-head{background:var(--black);padding:.85rem 1.1rem;display:flex;align-items:center;justify-content:space-between}
.ch-title{font-family:'Playfair Display',serif;font-size:.95rem;color:#fff;font-weight:500}
.ch-sub{font-size:.7rem;color:rgba(255,255,255,.45)}
.online-dot{width:7px;height:7px;background:#3cb97a;border-radius:50%;display:inline-block;margin-right:5px}
#chat-msgs{flex:1;overflow-y:auto;padding:1rem;display:flex;flex-direction:column;gap:.55rem;scrollbar-width:thin;scrollbar-color:#e5e3dc transparent}
.bubble{max-width:88%;padding:.55rem .85rem;border-radius:10px;font-size:.87rem;line-height:1.55;white-space:pre-line}
.bubble.bot{background:#f5f4f0;color:#333;align-self:flex-start;border-bottom-left-radius:3px}
.bubble.user{background:var(--black);color:#fff;align-self:flex-end;border-bottom-right-radius:3px}
.bubble.system{background:#eaf4ee;color:#2d7a4f;align-self:center;font-size:.8rem;border-radius:6px;text-align:center;padding:.4rem .75rem;max-width:95%}
.bubble.error{background:#f0f7fd;color:#2a6e9e;align-self:center;font-size:.8rem;border-radius:6px;text-align:center;padding:.4rem .75rem;max-width:95%}
.typing{display:flex;gap:4px;align-items:center;padding:.55rem .85rem;background:#f5f4f0;border-radius:10px;width:fit-content;border-bottom-left-radius:3px}
.typing span{width:6px;height:6px;background:#bbb;border-radius:50%;animation:bounce 1s infinite}
.typing span:nth-child(2){animation-delay:.15s}
.typing span:nth-child(3){animation-delay:.3s}
@keyframes bounce{0%,80%,100%{transform:translateY(0)}40%{transform:translateY(-5px)}}
#quick-btns{display:flex;flex-wrap:wrap;gap:.4rem;padding:0 .85rem .6rem}
#date-picker-row{display:none;padding:0 .85rem .7rem}
#date-picker-row.show{display:block}
#chat-date-input{width:100%;border:1.5px solid var(--border);border-radius:8px;padding:.65rem .75rem;font-family:'DM Sans',sans-serif;font-size:.88rem;color:var(--dark);background:#fff;outline:none}
#chat-date-input:focus{border-color:var(--black)}
.qbtn{background:transparent;border:1.5px solid var(--border);color:#555;padding:.3rem .65rem;border-radius:20px;font-size:.78rem;cursor:pointer;font-family:'DM Sans',sans-serif;transition:all .15s}
.qbtn:hover{border-color:var(--black);color:var(--black)}
#chat-input-row{display:flex;border-top:1.5px solid var(--border);padding:.5rem .75rem;gap:.5rem}
#chat-input{flex:1;background:transparent;border:none;color:var(--dark);font-family:'DM Sans',sans-serif;font-size:.88rem;outline:none;padding:.3rem}
#chat-input::placeholder{color:#bbb}
#chat-send{background:var(--black);color:#fff;border:none;padding:.4rem .85rem;border-radius:4px;cursor:pointer;font-family:'DM Sans',sans-serif;font-size:.82rem;transition:background .15s}
#chat-send:hover{background:var(--red)}
@media(max-width:640px){.about-grid,.contact-grid{grid-template-columns:1fr}.nav-links{gap:1rem}nav{padding:1rem 1.25rem}#chat-win{width:300px}.add-block-row{flex-direction:column}}
</style>
</head>
<body>

<nav>
  <a href="#" class="nav-logo" onclick="window.scrollTo({top:0,behavior:'smooth'});return false;">Ian &amp; Adrian<span> Car Cleaning</span></a>
  <ul class="nav-links">
    <li><a href="#services">Services</a></li>
    <li><a href="#about">About</a></li>
    <li><a href="#contact">Contact</a></li>
    <li><a href="#" class="nav-cta" onclick="openChat();return false;">Book Now</a></li>
  </ul>
</nav>

<section class="hero" id="home">
  <div class="hero-cars">
    <img src="data:image/png;base64," class="hero-car hero-car-left" alt="Silver car"/>
    <div class="hero-center">
      <div class="hero-eyebrow">Professional Car Detailing</div>
      <h1>Your Car Deserves<br/><em>the Best Clean</em></h1>
      <p>Expert detailing by Ian &amp; Adrian — we restore, protect, and transform every vehicle we touch.</p>
      <div class="hero-btns">
        <button class="btn-primary" onclick="openChat()">Book an Appointment</button>
        <button class="btn-outline" onclick="document.getElementById('services').scrollIntoView({behavior:'smooth'})">See Packages</button>
      </div>
    </div>
    <img src="data:image/png;base64," class="hero-car hero-car-right" alt="Brown car"/>
  </div>
</section>

<div class="stats">
  <div class="stat"><div class="stat-n">200+</div><div class="stat-l">Cars Detailed</div></div>
  <div class="stat"><div class="stat-n">5 ★</div><div class="stat-l">Average Rating</div></div>
  <div class="stat"><div class="stat-n">4</div><div class="stat-l">Service Tiers</div></div>
  <div class="stat"><div class="stat-n">100%</div><div class="stat-l">Satisfaction</div></div>
</div>

<section id="services">
  <div style="max-width:980px;margin:0 auto">
    <div class="sec-label">What We Offer</div>
    <div class="sec-title">Choose Your Package</div>
    <p class="sec-sub">Prices may vary depending on condition. Pricing depends on vehicle size. Coupe/Sedan pricing is listed first, with SUV pricing shown below. Custom jobs are quoted by phone.</p>
    <div class="tiers">
      <div class="tier">
        <div class="t-name">Basic</div>
        <div class="t-price"><sup>$</sup>79<sub> Coupe / Sedan</sub></div>
        <div class="t-price" style="font-size:1.4rem;margin-top:-.1rem"><sup>$</sup>99<sub> SUV</sub></div>
        <div class="t-desc">Essential clean — ideal for regular upkeep.</div>
        <ul class="t-features">
          <li>Exterior hand wash</li>
          <li>Wheel &amp; tire cleaning</li>
          <li>Window cleaning</li>
          <li>Interior vacuum</li>
          <li>Dashboard wipe-down</li>
        </ul>
        <button class="t-btn" onclick="bookService('Basic')">Book Basic →</button>
      </div>
      <div class="tier featured">
        <div class="t-badge">Most Popular</div>
        <div class="t-name">Standard</div>
        <div class="t-price"><sup>$</sup>149<sub> Coupe / Sedan</sub></div>
        <div class="t-price" style="font-size:1.4rem;margin-top:-.1rem"><sup>$</sup>179<sub> SUV</sub></div>
        <div class="t-desc">A thorough detail that goes beyond the surface.</div>
        <ul class="t-features">
          <li>Everything in Basic</li>
          <li>Clay bar treatment</li>
          <li>Interior deep clean</li>
          <li>Leather conditioning</li>
          <li>Odor elimination</li>
          <li>Tire dressing</li>
        </ul>
        <button class="t-btn" onclick="bookService('Standard')">Book Standard →</button>
      </div>
      <div class="tier">
        <div class="t-name">Premium</div>
        <div class="t-price"><sup>$</sup>249<sub> Coupe / Sedan</sub></div>
        <div class="t-price" style="font-size:1.4rem;margin-top:-.1rem"><sup>$</sup>289<sub> SUV</sub></div>
        <div class="t-desc">Showroom quality, zero compromise.</div>
        <ul class="t-features">
          <li>Everything in Standard</li>
          <li>Paint correction</li>
          <li>Ceramic coating</li>
          <li>Engine bay detail</li>
          <li>Headlight restoration</li>
          <li>Full interior steam clean</li>
        </ul>
        <button class="t-btn" onclick="bookService('Premium')">Book Premium →</button>
      </div>
      <div class="tier custom-tier">
        <div class="t-name">Custom</div>
        <div class="t-price" style="font-size:2rem">Custom Quote</div>
        <div class="t-desc">Need something different? Tell us what you want cleaned, restored, or protected and we can work out the final price on the phone.</div>
        <ul class="t-features">
          <li>Interior-only or exterior-only options</li>
          <li>Condition-based pricing</li>
          <li>Add-ons and special requests</li>
          <li>We will discuss the final price on the phone</li>
        </ul>
        <button class="t-btn" onclick="bookService('Custom')">Request Custom Quote →</button>
      </div>
    </div>
  </div>
</section>

<section id="about">
  <div class="about-grid" style="max-width:880px;margin:0 auto">
    <div class="about-text">
      <div class="sec-label">Who We Are</div>
      <div class="sec-title">Passion Behind<br/>Every Detail</div>
      <p>Ian and Adrian started this business with one goal: to give every car the care it deserves. We use premium products that are safe for your paint, tough on grime, and built to last.</p>
      <p>Whether it's your daily driver or a prized weekend car, we bring showroom results to your driveway from our base in Hackettstown, NJ. We cover up to 25 miles with no extra charge.</p>
    </div>
    <ul class="about-list">
      <li>Fully insured &amp; professional</li>
      <li>Premium eco-friendly products</li>
      <li>Mobile service available</li>
      <li>Satisfaction guaranteed</li>
      <li>Before &amp; after photos included</li>
      <li>Fast, reliable turnaround</li>
    </ul>
  </div>
</section>


<section id="gallery" style="background:var(--white);border-top:1px solid var(--border)">
  <div style="max-width:900px;margin:0 auto">
    <div class="sec-label">Our Work</div>
    <div class="sec-title">Before &amp; After</div>
    <p class="sec-sub">Real results from real cars. Every detail matters.</p>
    <div class="ba-stack">
      <div class="ba-card">
        <div class="ba-pair">
          <div class="ba-box ba-before"><span>Before</span></div>
          <div class="ba-box ba-after"><span>After</span></div>
        </div>
      </div>
      <div class="ba-card">
        <div class="ba-pair">
          <div class="ba-box ba-before"><span>Before</span></div>
          <div class="ba-box ba-after"><span>After</span></div>
        </div>
      </div>
      <div class="ba-card">
        <div class="ba-pair">
          <div class="ba-box ba-before"><span>Before</span></div>
          <div class="ba-box ba-after"><span>After</span></div>
        </div>
      </div>
    </div>
    <div class="socials-cta">
      <p>Want to see more of our work?</p>
      <p class="socials-sub">Check out our socials for the latest transformations 📸</p>
      <div class="socials-links">
        <a href="https://www.instagram.com/" target="_blank" rel="noopener" class="social-btn instagram-btn">📷 Instagram</a>
        <a href="https://www.facebook.com/" target="_blank" rel="noopener" class="social-btn facebook-btn">👍 Facebook</a>
      </div>
    </div>
  </div>
</section>

<section id="contact">
  <div class="contact-grid" style="max-width:800px;margin:0 auto">
    <div>
      <div class="sec-label">Contact</div>
      <div class="sec-title">Get in Touch</div>
      <p style="color:var(--muted);font-weight:300;margin-bottom:2rem;line-height:1.8">Questions? Ready to book? Use the chat or reach out directly.</p>
      <button class="btn-primary" onclick="openChat()">Open Booking Chat →</button>
    </div>
    <div>
      <div class="contact-row">
        <div class="c-icon">✉</div>
        <div><div class="c-label">Ian Email</div><div class="c-val"><a href="mailto:iandeithorn915@gmail.com">iandeithorn915@gmail.com</a></div></div>
      </div>
      <div class="contact-row">
        <div class="c-icon">✉</div>
        <div><div class="c-label">Adrian Email</div><div class="c-val"><a href="mailto:adrian.felix.chan@gmail.com">adrian.felix.chan@gmail.com</a></div></div>
      </div>
      <div class="contact-row">
        <div class="c-icon">🌐</div>
        <div><div class="c-label">Website</div><div class="c-val"><a href="https://ianadriancars.com">ianadriancars.com</a></div></div>
